1	// --- Rates, fees, and thresholds ---
2	const PROCESSING_FEE = 5;
3	const FIRST_INSURANCE_RATE = 0.1;
4	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
5	const LOYALTY_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const CURSE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	
15	// --- Item catalog ---
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	// --- Domain types ---
37	type Customer = { yearsWithMHPCO: number };
38	type Item = { type: string; cursed?: boolean; enchantment?: number };
39	type QuoteStep = { op: "quote"; items: Item[] };
40	type Damage = { itemType: string; amount: number };
41	type Incident = { cause: string; damages: Damage[] };
42	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
43	type Step = QuoteStep | ClaimStep;
44	type Input = { customer: Customer; steps: Step[] };
45	type QuoteResult = { premium: number };
46	type ClaimResult = { payout: number; remainingCap: number };
47	type StepResult = QuoteResult | ClaimResult;
48	
49	const countByType = (items: Item[]): Map<string, number> => {
50	  const counts = new Map<string, number>();
51	  for (const item of items) {
52	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
53	  }
54	  return counts;
55	};
56	
57	const basePremiumForType = (type: string, count: number): number => {
58	  const unit = BASE_PREMIUM[type];
59	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
60	    return BLOCK_BASE_PREMIUM;
61	  }
62	  return unit * count;
63	};
64	
65	const basePremium = (items: Item[]): number =>
66	  Array.from(countByType(items)).reduce(
67	    (total, [type, count]) => total + basePremiumForType(type, count),
68	    0,
69	  );
70	
71	// MHPCO always rounds premiums in its own favor (up).
72	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
73	
74	const isCursed = (item: Item): boolean => item.cursed === true;
75	const isHighlyEnchanted = (item: Item): boolean =>
76	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
77	
78	const itemSurcharge = (item: Item): number => {
79	  const unit = BASE_PREMIUM[item.type];
80	  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
81	  const enchantmentSurcharge = isHighlyEnchanted(item)
82	    ? unit * HIGH_ENCHANTMENT_RATE
83	    : 0;
84	  return curseSurcharge + enchantmentSurcharge;
85	};
86	
87	const sumItemSurcharges = (items: Item[]): number =>
88	  items.reduce((total, item) => total + itemSurcharge(item), 0);
89	
90	const isLoyalCustomer = (customer: Customer): boolean =>
91	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
92	
93	const loyaltyDiscount = (base: number, customer: Customer): number =>
94	  isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;
95	
96	const firstInsuranceSurcharge = (base: number): number =>
97	  base * FIRST_INSURANCE_RATE;
98	
99	const followUpDiscount = (base: number, stepIndex: number): number =>
100	  stepIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
101	
102	const quotePremium = (
103	  { items }: QuoteStep,
104	  customer: Customer,
105	  stepIndex: number,
106	): QuoteResult => {
107	  const base = basePremium(items);
108	  const premium =
109	    base +
110	    sumItemSurcharges(items) +
111	    firstInsuranceSurcharge(base) -
112	    loyaltyDiscount(base, customer) -
113	    followUpDiscount(base, stepIndex) +
114	    PROCESSING_FEE;
115	  return { premium: roundUpInMHPCOFavor(premium) };
116	};
117	
118	const insuranceSum = (items: Item[]): number =>
119	  items.reduce((total, item) => total + INSURANCE_VALUE[item.type], 0);
120	
121	const damagePayout = (amount: number): number =>
122	  Math.max(amount - DEDUCTIBLE, 0);
123	
124	const processClaim = (step: ClaimStep, steps: Step[]): ClaimResult => {
125	  const policyStep = steps[step.policy] as QuoteStep;
126	  const cap = CAP_MULTIPLIER * insuranceSum(policyStep.items);
127	  const payout = step.incident.damages.reduce(
128	    (total, damage) => total + damagePayout(damage.amount),
129	    0,
130	  );
131	  return { payout, remainingCap: cap - payout };
132	};
133	
134	const processStep = (step: Step, index: number, steps: Step[], customer: Customer): StepResult =>
135	  step.op === "quote"
136	    ? quotePremium(step, customer, index)
137	    : processClaim(step, steps);
138	
139	export const run = (input: Input): { results: StepResult[] } => ({
140	  results: input.steps.map((step, index) =>
141	    processStep(step, index, input.steps, input.customer),
142	  ),
143	});
