const insuranceSum = (items: Item[]): number =>
  items.reduce((total, item) => total + INSURANCE_VALUE[item.type], 0);

const policyCap = (items: Item[]): number =>
  CAP_MULTIPLIER * insuranceSum(items);

const damagePayout = (damage: Damage): number =>
  Math.max(damage.amount - DEDUCTIBLE, 0);

const totalPayout = (damages: Damage[]): number =>
  damages.reduce((total, damage) => total + damagePayout(damage), 0);

const processClaim = (step: ClaimStep, steps: Step[]): ClaimResult => {
  const policyStep = steps[step.policy] as QuoteStep;
  const payout = totalPayout(step.incident.damages);
  return { payout, remainingCap: policyCap(policyStep.items) - payout };
};
